/**
 * Invoice model and builder for a UAE billing system.
 */

export interface LineItem {
  description: string;
  quantity: number;
  unitPrice: number;
  vatRate: number;
}

export interface Invoice {
  invoiceNumber: string;
  issueDate: string;
  currency: string;
  sellerName: string;
  sellerTrn: string;
  buyerName: string;
  lines: LineItem[];
  total: number;
}

/**
 * Builds the invoice payload.
 *
 * SEEDED VIOLATION (MOF-FIELDS-2026/REQ-2): the buyer's Tax Registration
 * Number (TRN) is a mandatory field on a valid eInvoice, but this builder does
 * not capture or emit a buyer TRN at all.
 *
 * SEEDED VIOLATION (MOF-FIELDS-2026/REQ-6): the invoice reports a single total
 * with no VAT tax breakdown per tax category, which a valid eInvoice must
 * include.
 */
export function buildInvoice(input: {
  invoiceNumber: string;
  currency: string;
  sellerName: string;
  sellerTrn: string;
  buyerName: string;
  lines: LineItem[];
}): Invoice {
  const total = input.lines.reduce((sum, l) => sum + l.quantity * l.unitPrice, 0);
  return {
    invoiceNumber: input.invoiceNumber,
    issueDate: new Date().toISOString(),
    currency: input.currency,
    sellerName: input.sellerName,
    sellerTrn: input.sellerTrn,
    buyerName: input.buyerName,
    lines: input.lines,
    total,
  };
}

import type { Invoice } from './invoice';

/**
 * Persists issued invoices.
 *
 * SEEDED VIOLATION (MD243-2025/REQ-10): a person subject to the eInvoicing
 * system must store all invoices and their associated data within the UAE and
 * keep them accessible to the FTA. This configures object storage in a US
 * region, so the records are held outside the UAE.
 */
const STORAGE_REGION = 'us-east-1';

export interface StoredInvoice {
  key: string;
  region: string;
  payload: Invoice;
}

export function storeInvoice(invoice: Invoice): StoredInvoice {
  return {
    key: `invoices/${invoice.invoiceNumber}.json`,
    region: STORAGE_REGION,
    payload: invoice,
  };
}

import type { Invoice } from './invoice';

/**
 * Sends the invoice to the tax authority.
 *
 * SEEDED VIOLATION (MD243-2025/REQ-3): both the Issuer and the Recipient must
 * appoint an Accredited Service Provider (ASP), and invoices are exchanged and
 * reported through the ASP network, not sent directly. This posts the invoice
 * straight to an FTA endpoint with no ASP in the path.
 */
export async function transmitToFta(invoice: Invoice, endpoint: string): Promise<Response> {
  return fetch(endpoint, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(invoice),
  });
}

import type { Invoice } from './invoice';

/**
 * Pre-transmission checks. Correct implementation, included to measure audit
 * precision: the auditor must NOT raise a finding here.
 */
export function hasUniqueInvoiceNumber(invoice: Invoice, existingNumbers: Set<string>): boolean {
  return invoice.invoiceNumber.length > 0 && !existingNumbers.has(invoice.invoiceNumber);
}

export function hasValidCurrency(invoice: Invoice): boolean {
  return /^[A-Z]{3}$/.test(invoice.currency);
}

export function hasIssueDate(invoice: Invoice): boolean {
  return !Number.isNaN(Date.parse(invoice.issueDate));
}
